// O compilador gera um main() por baixo dos panos
@main
struct MeuAppApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()  // a primeira View do app
        }
    }
}

// App é um protocol com um requisito:
protocol App {
    associatedtype Body: Scene
    var body: Self.Body { get }  // igual ao protocol View, mas retorna Scene
}

// WindowGroup é a Scene mais comum — permite múltiplas janelas no iPadOS/macOS
@main
struct MeuAppApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}

// Outras Scenes úteis:
// DocumentGroup — para apps baseados em documentos
// Settings — painel de configurações no macOS
// MenuBarExtra — ícone na barra de menu do macOS

@main
struct MeuAppApp: App {
    // init roda UMA vez — ideal para configurações globais
    init() {
        // Configurar aparência global de UINavigationBar (interop UIKit)
        UINavigationBar.appearance().largeTitleTextAttributes = [
            .foregroundColor: UIColor.systemBlue
        ]
    }

    var body: some Scene {
        WindowGroup {
            ContentView()
                .modelContainer(for: Tarefa.self)  // SwiftData
        }
    }
}

// ERRADO — trabalho pesado no body:
struct MinhaView: View {
    var body: some View {
        let dados = carregarDoDiscoDeSincronamente()  // bloqueia o body!
        return Text(dados)
    }
}

// CORRETO — body descreve a UI, trabalho pesado fica em outros lugares:
struct MinhaView: View {
    @State private var dados = ""

    var body: some View {
        Text(dados)  // apenas descreve o layout
            .task {
                dados = await carregarDaRede()  // assíncrono, fora do body
            }
    }
}

struct ListaDeTarefas: View {
    @State private var tarefas: [Tarefa] = []

    var body: some View {
        List(tarefas) { tarefa in
            Text(tarefa.titulo)
        }
        .onAppear {
            // Cuidado: pode ser chamado mais de uma vez
            print("Lista apareceu")
            carregarTarefas()
        }
        .onDisappear {
            print("Lista sumiu da tela")
            cancelarBuscas()
        }
    }
}

struct PerfilView: View {
    let usuarioId: UUID
    @State private var perfil: Perfil?

    var body: some View {
        Group {
            if let perfil {
                Text(perfil.nome)
            } else {
                ProgressView()
            }
        }
        // task cancela a busca automaticamente se o usuário sair:
        .task {
            do {
                perfil = try await PerfilService.buscar(id: usuarioId)
            } catch {
                print("Erro: \(error)")
            }
        }
    }
}

// task com id — refaz a busca quando o id muda:
.task(id: filtro) {
    resultados = await buscar(filtro: filtro)
}

@main
struct MeuAppApp: App {
    @Environment(\.scenePhase) private var scenePhase

    var body: some Scene {
        WindowGroup {
            ContentView()
        }
        .onChange(of: scenePhase) { _, novaFase in
            switch novaFase {
            case .active:
                print("App ativo — usuário está interagindo")
            case .inactive:
                print("App inativo — em transição")
            case .background:
                print("App em segundo plano — salvar dados")
            @unknown default:
                break
            }
        }
    }
}

// Preview básico — instância direta da View:
#Preview {
    ContentView()
}

// Com nome — aparece no canvas como aba:
#Preview("Modo escuro") {
    ContentView()
        .preferredColorScheme(.dark)
}

// Múltiplos previews no mesmo arquivo:
#Preview("iPhone") {
    MinhaView()
}

#Preview("iPad") {
    MinhaView()
        .previewDevice("iPad Pro 11-inch (M4)")
}

// Dados de preview junto ao modelo:
extension Tarefa {
    static var preview: Tarefa {
        Tarefa(titulo: "Revisar PR", concluida: false)
    }

    static var previews: [Tarefa] {
        [
            Tarefa(titulo: "Revisar PR", concluida: false),
            Tarefa(titulo: "Escrever testes", concluida: true),
            Tarefa(titulo: "Um título muito longo que vai quebrar o layout de formas interessantes", concluida: false)
        ]
    }
}

// Preview usando os dados de exemplo:
#Preview("Lista cheia") {
    ListaDeTarefasView(tarefas: Tarefa.previews)
}

#Preview("Lista vazia") {
    ListaDeTarefasView(tarefas: [])
}

// DIFÍCIL de testar em Preview — acessa dados globais:
struct PerfilView: View {
    var body: some View {
        Text(SessaoAtual.shared.usuario.nome)  // Preview não tem SessaoAtual
    }
}

// FÁCIL de testar em Preview — dados são parâmetro:
struct PerfilView: View {
    let usuario: Usuario  // recebe por injeção

    var body: some View {
        Text(usuario.nome)
    }
}

#Preview {
    PerfilView(usuario: Usuario.preview)  // funciona no canvas
}
